  1146→      [] as string[],
  1147→    )
  1148→    .option(
  1149→      "--block-reason <reason>",
  1150→      "Message sent to Claude when a tool is blocked",
  1151→      "Blocked by claude-hook-handler",
  1152→    )
  1153→    .option(
  1154→      "--no-summary",
  1155→      "Skip AI summarisation, use truncated prompt text instead",
  1156→    )
  1157→    .option(
  1158→      "--max-log-lines <n>",
  1159→      "Rotate session log files after this many lines (0 to disable)",
  1160→      (v: string) => parseInt(v, 10),
  1161→      1000,
  1162→    )
  1163→    .option("--quiet", "Suppress stderr output")
  1164→    .action(async () => {
  1165→      const opts = program.opts<{
