  1195→        process.exit(1);
  1196→      }
  1197→
  1198→      const blocked = shouldBlock(input, blockPatterns);
  1199→
  1200→      if (input.hook_event_name !== "Setup") {
  1201→        try {
  1202→          const db = await getDb(expandHome(opts.db));
  1203→          const state = await readStateFromDb(db);
  1204→
  1205→          // Auto-link plan→implementation sessions: a SessionStart that fires within
  1206→          // 30 s of a SessionEnd in the same cwd is treated as a continuation.
  1207→          if (input.hook_event_name === "SessionStart" && !state.agentParents[input.session_id]) {
  1208→            const recentEnd = await db.event.findFirst({
  1209→              where: { event: "SessionEnd", timestamp: { gte: new Date(Date.now() - 30_000) } },
  1210→              orderBy: { timestamp: "desc" },
  1211→            });
  1212→            if (recentEnd) {
  1213→              const prev = await db.session.findUnique({
