  1218→                state.agentParents[input.session_id] = recentEnd.sessionId;
  1219→              }
  1220→            }
  1221→          }
  1222→
  1223→          // 1. Compute derived state (summary/keywords via AI if needed)
  1224→          await applyEvent(state, input, noSummary);
  1225→
  1226→          // 2. Write to SQLite event log — primary source of truth
  1227→          await writeEventLog(db, input, blocked, state);
