     1→import React, { useCallback, useEffect, useMemo, useState } from "react";
     2→import {
     3→  View,
     4→  Text,
     5→  TouchableOpacity,
     6→  StyleSheet,
     7→  useWindowDimensions,
     8→} from "react-native";
     9→import { useHeaderHeight } from "@react-navigation/elements";
    10→import type { StackScreenProps } from "@react-navigation/stack";
    11→import type { RootStackParamList } from "../../App";
    12→import { fetchSessions, subscribeToUpdates, type Session } from "../api";
    13→
    14→type Props = StackScreenProps<RootStackParamList, "SessionTree">;
    15→
    16→// ─── Tree building ────────────────────────────────────────────────────────────
    17→
    18→interface FlatNode {
    19→  session: Session;
    20→  depth: number;
    21→  hasChildren: boolean;
    22→  isLast: boolean; // last sibling at this level
    23→}
    24→
    25→function buildChildMap(sessions: Session[]): Map<string | null, Session[]> {
    26→  const map = new Map<string | null, Session[]>();
    27→  for (const s of sessions) {
    28→    const key = s.parentSessionId;
    29→    if (!map.has(key)) map.set(key, []);
    30→    // sort siblings newest-first
    31→    map.get(key)!.push(s);
    32→  }
    33→  // sort each sibling group newest-first
    34→  for (const arr of map.values()) {
    35→    arr.sort((a, b) => (a.startedAt < b.startedAt ? 1 : -1));
    36→  }
    37→  return map;
    38→}
    39→
    40→function flatten(
    41→  parentId: string | null,
    42→  childMap: Map<string | null, Session[]>,
    43→  depth: number,
    44→  expanded: Set<string>,
    45→  out: FlatNode[],
    46→) {
    47→  const siblings = childMap.get(parentId) ?? [];
    48→  for (let i = 0; i < siblings.length; i++) {
    49→    const session = siblings[i];
    50→    const hasChildren = (childMap.get(session.sessionId) ?? []).length > 0;
    51→    const isLast = i === siblings.length - 1;
    52→    out.push({ session, depth, hasChildren, isLast });
    53→    if (hasChildren && expanded.has(session.sessionId)) {
    54→      flatten(session.sessionId, childMap, depth + 1, expanded, out);
    55→    }
    56→  }
    57→}
    58→
    59→// ─── Helpers ──────────────────────────────────────────────────────────────────
    60→
    61→function relativeTime(iso: string): string {
    62→  const diff = Date.now() - new Date(iso).getTime();
    63→  const s = Math.floor(diff / 1000);
    64→  if (s < 60)  return `${s}s ago`;
    65→  if (s < 3600) return `${Math.floor(s / 60)}m ago`;
    66→  if (s < 86400) return `${Math.floor(s / 3600)}h ago`;
    67→  return `${Math.floor(s / 86400)}d ago`;
    68→}
    69→
    70→function activityColor(iso: string): string {
    71→  const diff = Date.now() - new Date(iso).getTime();
    72→  if (diff < 2 * 60 * 1000)  return "#22c55e"; // active  < 2 min
    73→  if (diff < 15 * 60 * 1000) return "#f59e0b"; // recent  < 15 min
    74→  return "#d1d5db";                             // ended
    75→}
    76→
    77→// ─── Node row ─────────────────────────────────────────────────────────────────
    78→
    79→const INDENT = 22;
    80→
    81→interface NodeProps {
    82→  node: FlatNode;
    83→  isExpanded: boolean;
    84→  onPress: () => void;
    85→  onToggle: () => void;
    86→}
    87→
    88→function TreeNode({ node, isExpanded, onPress, onToggle }: NodeProps) {
    89→  const { session, depth, hasChildren } = node;
    90→  const dotColor = activityColor(session.updatedAt);
    91→
    92→  return (
    93→    <TouchableOpacity
    94→      style={[s.row, { paddingLeft: 12 + depth * INDENT }]}
    95→      onPress={onPress}
    96→      activeOpacity={0.7}
    97→    >
    98→      {/* Expand/collapse toggle — only rendered for parent nodes */}
    99→      <TouchableOpacity
   100→        onPress={hasChildren ? onToggle : onPress}
   101→        hitSlop={{ top: 8, bottom: 8, left: 8, right: 8 }}
   102→        style={s.toggleWrap}
   103→      >
   104→        {hasChildren ? (
   105→          <Text style={s.chevron}>{isExpanded ? "▼" : "▶"}</Text>
   106→        ) : (
   107→          <View style={[s.leaf, { backgroundColor: dotColor }]} />
   108→        )}
   109→      </TouchableOpacity>
   110→
   111→      {/* Activity dot for parent nodes */}
   112→      {hasChildren && <View style={[s.dot, { backgroundColor: dotColor }]} />}
   113→
   114→      {/* Content */}
   115→      <View style={s.content}>
   116→        <View style={s.titleRow}>
   117→          <Text style={s.sessionId}>{session.sessionId.slice(0, 8)}</Text>
   118→          {session.repoName && (
   119→            <Text style={s.repoChip}>{session.repoName}</Text>
   120→          )}
   121→          <Text style={s.time}>{relativeTime(session.updatedAt)}</Text>
   122→        </View>
   123→        {session.summary && (
   124→          <Text style={s.summary} numberOfLines={2}>{session.summary}</Text>
   125→        )}
   126→        {session.keywords.length > 0 && (
   127→          <View style={s.keywords}>
   128→            {session.keywords.slice(0, 5).map((k) => (
   129→              <Text key={k} style={s.keyword}>{k}</Text>
   130→            ))}
   131→          </View>
   132→        )}
   133→      </View>
   134→    </TouchableOpacity>
   135→  );
   136→}
   137→
   138→// ─── Screen ───────────────────────────────────────────────────────────────────
   139→
   140→export function SessionTree({ navigation }: Props) {
   141→  const [sessions, setSessions] = useState<Session[]>([]);
   142→  const [loading, setLoading] = useState(true);
   143→  const [error, setError] = useState<string | null>(null);
   144→  const [expanded, setExpanded] = useState<Set<string>>(new Set());
   145→
   146→  const { height } = useWindowDimensions();
   147→  const headerHeight = useHeaderHeight();
   148→  const contentHeight = height - headerHeight;
   149→
   150→  const load = useCallback(async () => {
   151→    try {
   152→      const data = await fetchSessions();
   153→      setSessions(data);
   154→      setError(null);
   155→      // auto-expand all nodes that have children
   156→      setExpanded((prev) => {
   157→        const next = new Set(prev);
   158→        const parentIds = new Set(data.map((s) => s.parentSessionId).filter(Boolean));
   159→        for (const id of parentIds) if (id) next.add(id);
   160→        return next;
   161→      });
   162→    } catch (e) {
   163→      setError(String(e));
   164→    }
   165→  }, []);
   166→
   167→  useEffect(() => {
   168→    load().finally(() => setLoading(false));
   169→    return subscribeToUpdates(() => { load().catch(() => undefined); });
   170→  }, [load]);
   171→
   172→  const childMap = useMemo(() => buildChildMap(sessions), [sessions]);
   173→
   174→  const nodes = useMemo(() => {
   175→    const out: FlatNode[] = [];
   176→    flatten(null, childMap, 0, expanded, out);
   177→    return out;
   178→  }, [childMap, expanded]);
   179→
   180→  function toggle(sessionId: string) {
   181→    setExpanded((prev) => {
   182→      const next = new Set(prev);
   183→      if (next.has(sessionId)) next.delete(sessionId);
   184→      else next.add(sessionId);
   185→      return next;
   186→    });
   187→  }
   188→
   189→  if (loading) {
   190→    return (
   191→      <View style={s.centered}>
   192→        <Text style={s.loadingText}>Loading…</Text>
   193→      </View>
   194→    );
   195→  }
   196→
   197→  if (error) {
   198→    return (
   199→      <View style={s.centered}>
   200→        <Text style={s.errorText}>{error}</Text>
   201→      </View>
   202→    );
   203→  }
   204→
   205→  if (nodes.length === 0) {
   206→    return (
   207→      <View style={s.centered}>
   208→        <Text style={s.emptyText}>No sessions yet.</Text>
   209→      </View>
   210→    );
   211→  }
   212→
   213→  return (
   214→    <View style={[s.scroll, { height: contentHeight }]}>
   215→      {nodes.map((node, i) => {
   216→        const isExpanded = expanded.has(node.session.sessionId);
   217→        return (
   218→          <View key={node.session.sessionId}>
