import React, { useEffect, useMemo, useState } from "react";
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  useWindowDimensions,
} from "react-native";
import { useHeaderHeight } from "@react-navigation/elements";
import type { StackScreenProps } from "@react-navigation/stack";
import type { RootStackParamList } from "../../App";
import { fetchCheckpointMessages, type CheckpointMessage } from "../api";
import { CheckpointMessageItem, type ToolResultBlock } from "../components/CheckpointMessageItem";

type Props = StackScreenProps<RootStackParamList, "CheckpointDetail">;

// ─── Screen ───────────────────────────────────────────────────────────────────

export function CheckpointDetail({ route }: Props) {
  const { checkpointId } = route.params;
  const [messages, setMessages] = useState<CheckpointMessage[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showCompact, setShowCompact] = useState(false);

  const { height } = useWindowDimensions();
  const headerHeight = useHeaderHeight();
  const contentHeight = height - headerHeight;

  useEffect(() => {
    fetchCheckpointMessages(checkpointId)
      .then((msgs) => { setMessages(msgs); setError(null); })
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [checkpointId]);

  // Build a map from tool_use_id → tool_result block for rendering paired outputs
  const toolResults = useMemo(() => {
    const map = new Map<string, ToolResultBlock>();
    for (const msg of messages) {
      if (msg.type !== "user") continue;
      const d = msg.data as Record<string, unknown>;
      const content = (d.message as Record<string, unknown> | undefined)?.content;
      if (!Array.isArray(content)) continue;
      for (const block of content as ToolResultBlock[]) {
        if (block.type === "tool_result" && block.tool_use_id) {
          map.set(block.tool_use_id, block);
        }
      }
    }
    return map;
  }, [messages]);

  if (loading) {
    return (
      <View style={s.centered}>
        <ActivityIndicator size="large" color="#059669" />
      </View>
    );
  }

  if (error) {
    return (
      <View style={s.centered}>
        <Text style={s.errorText}>{error}</Text>
      </View>
    );
  }

  const counts = messages.reduce<Record<string, number>>((acc, m) => {
    acc[m.type] = (acc[m.type] ?? 0) + 1;
    return acc;
  }, {});

  return (
    <View style={[s.scroll, { height: contentHeight }]}>
      {/* Stats bar */}
      <View style={s.statsBar}>
        {Object.entries(counts).map(([type, count]) => (
          <View key={type} style={s.statChip}>
            <Text style={s.statText}>{type} {count}</Text>
          </View>
        ))}
        <TouchableOpacity
          style={[s.filterBtn, showCompact && s.filterBtnActive]}
          onPress={() => setShowCompact((v) => !v)}
        >
          <Text style={[s.filterBtnText, showCompact && s.filterBtnTextActive]}>
            {showCompact ? "▲ hide system" : "▼ show system"}
          </Text>
        </TouchableOpacity>
      </View>

      {/* Message list */}
      {messages.length === 0 ? (
        <View style={s.centered}>
          <Text style={s.emptyText}>No messages in this checkpoint.</Text>
        </View>
      ) : (
        messages.map((msg) => (
          <CheckpointMessageItem
            key={msg.uuid}
            msg={msg}
            toolResults={toolResults}
            showCompact={showCompact}
          />
        ))
      )}
    </View>
  );
}

// ─── Styles ───────────────────────────────────────────────────────────────────

const s = StyleSheet.create({
  scroll: {
    backgroundColor: "#fff",
    overflow: "scroll",
  },
  centered: {
    alignItems: "center",
    justifyContent: "center",
    padding: 24,
    minHeight: 120,
  },
  statsBar: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 6,
    alignItems: "center",
    paddingHorizontal: 12,
    paddingVertical: 8,
    backgroundColor: "#f8fafc",
    borderBottomWidth: 1,
    borderBottomColor: "#e5e7eb",
  },
  statChip: {
    backgroundColor: "#e2e8f0",
    borderRadius: 4,
    paddingHorizontal: 7,
    paddingVertical: 2,
  },
  statText: {
    fontSize: 11,
    color: "#475569",
    fontFamily: "monospace",
  },
  filterBtn: {
    marginLeft: "auto",
    borderRadius: 4,
    paddingHorizontal: 8,
    paddingVertical: 3,
    borderWidth: 1,
    borderColor: "#cbd5e1",
  },
  filterBtnActive: {
    backgroundColor: "#0f172a",
    borderColor: "#0f172a",
  },
  filterBtnText: {
    fontSize: 11,
    color: "#64748b",
  },
  filterBtnTextActive: {
    color: "#f8fafc",
  },
  errorText: {
    fontSize: 14,
    color: "#ef4444",
    textAlign: "center",
  },
  emptyText: {
    fontSize: 14,
    color: "#9ca3af",
  },
});

