     1→import React, { useEffect, useState } from "react";
     2→import {
     3→  View,
     4→  Text,
     5→  StyleSheet,
     6→  ActivityIndicator,
     7→  TouchableOpacity,
     8→  useWindowDimensions,
     9→} from "react-native";
    10→import { useHeaderHeight } from "@react-navigation/elements";
    11→import type { StackScreenProps } from "@react-navigation/stack";
    12→import type { RootStackParamList } from "../../App";
    13→import { fetchSession, fetchSessionEvents, fetchSessionOverview, type Session, type Event, type InteractionOverview } from "../api";
    14→import { EventItem } from "../components/EventItem";
    15→import { ToolGroupItem, type ToolUseData } from "../components/ToolGroupItem";
    16→
    17→type Props = StackScreenProps<RootStackParamList, "SessionDetail">;
    18→
    19→// ─── Event grouping ───────────────────────────────────────────────────────────
    20→
    21→type DisplayItem =
    22→  | { kind: "event"; event: Event }
    23→  | { kind: "toolGroup"; tools: ToolUseData[] };
    24→
    25→function groupEvents(events: Event[]): DisplayItem[] {
    26→  // Pass 1: pair PreToolUse with its matching PostToolUse
    27→  const postMap = new Map<string, Event>();
    28→  for (const event of events) {
    29→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
    30→      const d = event.data as Record<string, unknown>;
    31→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    32→      if (id) postMap.set(id, event);
    33→    }
    34→  }
    35→
    36→  type RawItem =
    37→    | { kind: "event"; event: Event }
    38→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
    39→
    40→  const raw: RawItem[] = [];
    41→  const consumed = new Set<number>();
    42→
    43→  for (const event of events) {
    44→    if (
    45→      (event.event === "PostToolUse" || event.event === "PostToolUseFailure") &&
    46→      consumed.has(event.id)
    47→    ) {
    48→      continue;
    49→    }
    50→    if (event.event === "PreToolUse") {
    51→      const d = event.data as Record<string, unknown>;
    52→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    53→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
    54→      if (post) consumed.add(post.id);
    55→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
    56→      continue;
    57→    }
    58→    raw.push({ kind: "event", event });
    59→  }
    60→
    61→  // Pass 2: collapse consecutive toolUse + Notification items into toolGroup.
    62→  // Notifications are absorbed silently (they're mostly "permission needed" noise).
    63→  const isGroupable = (item: RawItem) =>
    64→    item.kind === "toolUse" ||
    65→    (item.kind === "event" && item.event.event === "Notification");
    66→
    67→  const result: DisplayItem[] = [];
    68→  let i = 0;
    69→  while (i < raw.length) {
    70→    if (isGroupable(raw[i])) {
    71→      const group: ToolUseData[] = [];
    72→      while (i < raw.length && isGroupable(raw[i])) {
    73→        const item = raw[i];
    74→        if (item.kind === "toolUse") {
    75→          group.push({ pre: item.pre, post: item.post, failed: item.failed });
    76→        }
    77→        // Notifications are swallowed — don't add to group
    78→        i++;
    79→      }
    80→      if (group.length > 0) {
    81→        result.push({ kind: "toolGroup", tools: group });
    82→      }
    83→      // If the run was notifications-only, they're silently dropped
    84→    } else {
    85→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
    86→      i++;
    87→    }
    88→  }
    89→
    90→  return result;
    91→}
    92→
    93→// ─── Screen ───────────────────────────────────────────────────────────────────
    94→
    95→export function SessionDetail({ route, navigation }: Props) {
    96→  const { sessionId } = route.params;
    97→  const [session, setSession] = useState<Session | null>(null);
    98→  const [overview, setOverview] = useState<InteractionOverview | null>(null);
    99→  const [items, setItems] = useState<DisplayItem[]>([]);
   100→  const [loading, setLoading] = useState(true);
   101→  const [error, setError] = useState<string | null>(null);
   102→
   103→  const { height } = useWindowDimensions();
   104→  const headerHeight = useHeaderHeight();
   105→  const contentHeight = height - headerHeight;
   106→
   107→  useEffect(() => {
   108→    Promise.all([
   109→      fetchSession(sessionId),
   110→      fetchSessionEvents(sessionId),
   111→      fetchSessionOverview(sessionId),
   112→    ])
   113→      .then(([s, evs, ov]) => {
   114→        setSession(s);
   115→        setItems(groupEvents(evs));
   116→        setOverview(ov);
   117→        setError(null);
   118→      })
   119→      .catch((err: unknown) => setError(String(err)))
   120→      .finally(() => setLoading(false));
   121→  }, [sessionId]);
   122→
   123→  if (loading) {
   124→    return (
   125→      <View style={styles.centered}>
   126→        <ActivityIndicator size="large" color="#6366f1" />
   127→      </View>
   128→    );
   129→  }
   130→
   131→  if (error) {
   132→    return (
   133→      <View style={styles.centered}>
   134→        <Text style={styles.errorText}>{error}</Text>
   135→      </View>
   136→    );
   137→  }
   138→
   139→  return (
