   141→      {session?.parentSessionId && (
   142→        <TouchableOpacity
   143→          style={styles.parentBanner}
   144→          onPress={() =>
   145→            navigation.push("SessionDetail", {
   146→              sessionId: session.parentSessionId!,
   147→              title: session.parentSessionId!.slice(0, 8) + "…",
   148→            })
   149→          }
   150→        >
   151→          <Text style={styles.parentLabel}>↑ Continuation of</Text>
   152→          <Text style={styles.parentId}>{session.parentSessionId.slice(0, 8)}…</Text>
   153→        </TouchableOpacity>
   154→      )}
   155→
   156→      {session?.childSessionIds?.map((childId) => (
