   163→              title: childId.slice(0, 8) + "…",
   164→            })
   165→          }
   166→        >
   167→          <Text style={styles.childLabel}>↓ Continued as</Text>
   168→          <Text style={styles.childId}>{childId.slice(0, 8)}…</Text>
   169→        </TouchableOpacity>
   170→      ))}
   171→
   172→      {overview && (
   173→        <View style={styles.overviewCard}>
