   185→          <Text style={styles.overviewTime}>
   186→            {new Date(overview.startedAt).toLocaleString()} → {new Date(overview.endedAt).toLocaleString()}
   187→          </Text>
   188→        </View>
   189→      )}
   190→
   191→      {items.length === 0 ? (
