    backgroundColor: "#fde68a",
    paddingHorizontal: 5,
    paddingVertical: 1,
    borderRadius: 3,
  },
  emptyMsg: {
    fontSize: 13,
    color: "#9ca3af",
    fontStyle: "italic",
  },

  // Notification
  notifRow: {
    flexDirection: "row",
    alignItems: "center",
    gap: 8,
    paddingVertical: 5,
    paddingHorizontal: 12,
    borderBottomWidth: 1,
    borderBottomColor: "#f1f5f9",
  },
  notifSym: {
    fontSize: 13,
    fontWeight: "700",
    width: 16,
    textAlign: "center",
  },
  notifMsg: {
    fontSize: 12,
    flex: 1,
  },

  // Session
  sessionRow: {
    flexDirection: "row",
    alignItems: "flex-start",
    gap: 8,
    paddingVertical: 6,
    paddingHorizontal: 12,
    borderBottomWidth: 1,
    borderBottomColor: "#f1f5f9",
  },
  sessionSym: {
    fontSize: 14,
    fontWeight: "bold",
    width: 18,
    textAlign: "center",
    lineHeight: 20,
  },
  sessionBody: {
    flex: 1,
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 6,
    alignItems: "center",
  },
  sessionEvent: {
    fontSize: 12,
    fontWeight: "600",
  },
  sessionExtra: {
    fontSize: 11,
    color: "#6b7280",
    backgroundColor: "#f3f4f6",
    paddingHorizontal: 5,
    paddingVertical: 1,
    borderRadius: 3,
  },
  sessionCwd: {
    fontSize: 10,
