    textAlign: "center",
  },
  compactEvent: {
    fontSize: 11,
    fontWeight: "600",
    flex: 1,
  },
  compactTime: {
    fontSize: 10,
    color: "#9ca3af",
    marginLeft: "auto",
  },
  compactBody: {
    width: "100%",
