  chevron: {
    fontSize: 9,
    color: "#9ca3af",
  },

  // Shared
  blockedBadge: {
    backgroundColor: "#ef4444",
    borderRadius: 3,
    paddingHorizontal: 4,
    paddingVertical: 1,
