    paddingHorizontal: 12,
    borderBottomWidth: 1,
    borderBottomColor: "#f1f5f9",
  },
  notifSym: {
    fontSize: 13,
    fontWeight: "700",
    width: 16,
    textAlign: "center",
  },
  notifMsg: {
    fontSize: 12,
