     1→import React, { useMemo } from "react";
     2→import { View, Text, StyleSheet, type TextStyle } from "react-native";
     3→
     4→// ─── Inline types ─────────────────────────────────────────────────────────────
     5→
     6→type InlineNode =
     7→  | { t: "text"; s: string }
     8→  | { t: "bold"; s: string }
     9→  | { t: "italic"; s: string }
    10→  | { t: "code"; s: string };
    11→
    12→function parseInline(raw: string): InlineNode[] {
    13→  const nodes: InlineNode[] = [];
    14→  // Match **bold**, *italic*, `code` — non-greedy, no newlines inside delimiters
    15→  const re = /(\*\*(?:[^*]|\*(?!\*))+?\*\*|\*(?:[^*\n])+?\*|`[^`\n]+?`)/g;
    16→  let last = 0;
    17→  let m: RegExpExecArray | null;
    18→  while ((m = re.exec(raw)) !== null) {
    19→    if (m.index > last) nodes.push({ t: "text", s: raw.slice(last, m.index) });
    20→    const tok = m[1];
    21→    if (tok.startsWith("**")) nodes.push({ t: "bold", s: tok.slice(2, -2) });
    22→    else if (tok.startsWith("`")) nodes.push({ t: "code", s: tok.slice(1, -1) });
    23→    else nodes.push({ t: "italic", s: tok.slice(1, -1) });
    24→    last = m.index + tok.length;
    25→  }
    26→  if (last < raw.length) nodes.push({ t: "text", s: raw.slice(last) });
    27→  return nodes;
    28→}
    29→
    30→// ─── Block types ─────────────────────────────────────────────────────────────
    31→
    32→type Block =
    33→  | { kind: "code"; lang: string; code: string }
    34→  | { kind: "h"; level: 1 | 2 | 3; inline: InlineNode[] }
    35→  | { kind: "bullets"; items: InlineNode[][] }
    36→  | { kind: "numbered"; items: InlineNode[][] }
    37→  | { kind: "hr" }
    38→  | { kind: "table"; headers: InlineNode[][]; rows: InlineNode[][][] }
    39→  | { kind: "para"; inline: InlineNode[] };
    40→
    41→function parseBlocks(md: string): Block[] {
    42→  const lines = md.split("\n");
    43→  const out: Block[] = [];
    44→  let i = 0;
    45→
    46→  while (i < lines.length) {
    47→    const line = lines[i];
    48→
    49→    // Fenced code block
    50→    if (line.startsWith("```")) {
    51→      const lang = line.slice(3).trim();
    52→      const codeLines: string[] = [];
    53→      i++;
    54→      while (i < lines.length && !lines[i].startsWith("```")) codeLines.push(lines[i++]);
    55→      if (i < lines.length) i++; // skip closing ```
    56→      out.push({ kind: "code", lang, code: codeLines.join("\n") });
    57→      continue;
    58→    }
    59→
    60→    // ATX heading
    61→    const hm = line.match(/^(#{1,3}) (.+)/);
    62→    if (hm) {
    63→      out.push({ kind: "h", level: hm[1].length as 1 | 2 | 3, inline: parseInline(hm[2]) });
    64→      i++;
    65→      continue;
    66→    }
    67→
    68→    // Horizontal rule
    69→    if (/^([-*_])\1{2,}$/.test(line.trim())) {
    70→      out.push({ kind: "hr" });
    71→      i++;
    72→      continue;
    73→    }
    74→
    75→    // Bullet list
    76→    if (/^[-*+] /.test(line)) {
    77→      const items: InlineNode[][] = [];
    78→      while (i < lines.length && /^[-*+] /.test(lines[i])) {
    79→        items.push(parseInline(lines[i].slice(2)));
    80→        i++;
    81→      }
    82→      out.push({ kind: "bullets", items });
    83→      continue;
    84→    }
    85→
    86→    // Numbered list
    87→    if (/^\d+\. /.test(line)) {
    88→      const items: InlineNode[][] = [];
    89→      while (i < lines.length && /^\d+\. /.test(lines[i])) {
    90→        items.push(parseInline(lines[i].replace(/^\d+\. /, "")));
    91→        i++;
    92→      }
    93→      out.push({ kind: "numbered", items });
    94→      continue;
    95→    }
    96→
    97→    // GFM table — header row followed by separator row (|---|---|)
    98→    if (line.includes("|") && i + 1 < lines.length && /^\|?[\s|:=-]*-+[\s|:=-]*\|?$/.test(lines[i + 1])) {
    99→      const parseCells = (l: string): InlineNode[][] =>
   100→        l.replace(/^\|/, "").replace(/\|$/, "").split("|").map((c) => parseInline(c.trim()));
   101→      const headers = parseCells(line);
   102→      i += 2; // skip separator
   103→      const rows: InlineNode[][][] = [];
   104→      while (i < lines.length && lines[i].includes("|")) {
   105→        rows.push(parseCells(lines[i]));
   106→        i++;
   107→      }
   108→      out.push({ kind: "table", headers, rows });
   109→      continue;
   110→    }
   111→
   112→    // Empty line
   113→    if (line.trim() === "") { i++; continue; }
   114→
   115→    // Paragraph — accumulate until empty line or block-level element
   116→    const isTableStart = (j: number) =>
   117→      lines[j].includes("|") &&
   118→      j + 1 < lines.length &&
   119→      /^\|?[\s|:=-]*-+[\s|:=-]*\|?$/.test(lines[j + 1]);
   120→    const paraLines: string[] = [];
   121→    while (
   122→      i < lines.length &&
   123→      lines[i].trim() !== "" &&
   124→      !lines[i].startsWith("```") &&
   125→      !/^#{1,3} /.test(lines[i]) &&
   126→      !/^[-*+] /.test(lines[i]) &&
   127→      !/^\d+\. /.test(lines[i]) &&
   128→      !/^([-*_])\1{2,}$/.test(lines[i].trim()) &&
   129→      !isTableStart(i)
   130→    ) {
   131→      paraLines.push(lines[i]);
   132→      i++;
   133→    }
   134→    if (paraLines.length > 0) {
   135→      out.push({ kind: "para", inline: parseInline(paraLines.join(" ")) });
   136→    }
   137→  }
   138→
   139→  return out;
   140→}
   141→
   142→// ─── Inline renderer ─────────────────────────────────────────────────────────
   143→
   144→function Inline({ nodes }: { nodes: InlineNode[] }) {
   145→  return (
   146→    <>
   147→      {nodes.map((n, i) => {
   148→        if (n.t === "bold") return <Text key={i} style={s.bold}>{n.s}</Text>;
   149→        if (n.t === "italic") return <Text key={i} style={s.italic}>{n.s}</Text>;
   150→        if (n.t === "code") return <Text key={i} style={s.inlineCode}>{n.s}</Text>;
   151→        return <Text key={i}>{n.s}</Text>;
   152→      })}
   153→    </>
   154→  );
   155→}
   156→
   157→// ─── Public components ────────────────────────────────────────────────────────
   158→
   159→// Renders a single line of inline markdown (bold, italic, code) inside a Text.
   160→export function InlineMarkdown({
   161→  text,
   162→  style,
   163→  numberOfLines,
   164→}: {
   165→  text: string;
   166→  style?: TextStyle;
   167→  numberOfLines?: number;
   168→}) {
   169→  const nodes = useMemo(() => parseInline(text), [text]);
   170→  return (
   171→    <Text style={style} numberOfLines={numberOfLines}>
   172→      <Inline nodes={nodes} />
   173→    </Text>
   174→  );
   175→}
   176→
   177→export function MarkdownView({ text }: { text: string }) {
   178→  const blocks = useMemo(() => parseBlocks(text), [text]);
   179→
   180→  return (
   181→    <View>
   182→      {blocks.map((block, idx) => {
   183→        if (block.kind === "code") {
   184→          return (
   185→            <View key={idx} style={s.codeBlock}>
   186→              {block.lang ? <Text style={s.codeLang}>{block.lang}</Text> : null}
   187→              <Text style={s.codeText} selectable>{block.code}</Text>
   188→            </View>
   189→          );
   190→        }
   191→
   192→        if (block.kind === "h") {
   193→          const hs = block.level === 1 ? s.h1 : block.level === 2 ? s.h2 : s.h3;
   194→          return (
   195→            <Text key={idx} style={hs}>
   196→              <Inline nodes={block.inline} />
   197→            </Text>
   198→          );
   199→        }
   200→
   201→        if (block.kind === "hr") {
   202→          return <View key={idx} style={s.hr} />;
   203→        }
   204→
   205→        if (block.kind === "table") {
   206→          const colCount = block.headers.length;
   207→          return (
   208→            <View key={idx} style={s.table}>
   209→              <View style={[s.tableRow, s.tableHeaderRow]}>
   210→                {block.headers.map((h, j) => (
   211→                  <Text key={j} style={[s.tableCell, s.tableHeaderCell, { flex: 1 / colCount }]}>
   212→                    <Inline nodes={h} />
   213→                  </Text>
   214→                ))}
   215→              </View>
   216→              {block.rows.map((row, j) => (
   217→                <View key={j} style={[s.tableRow, j % 2 === 1 && s.tableRowAlt]}>
   218→                  {row.map((cell, k) => (
   219→                    <Text key={k} selectable style={[s.tableCell, { flex: 1 / colCount }]}>
