    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !lines[i].startsWith("```") &&
      !/^#{1,3} /.test(lines[i]) &&
      !/^[-*+] /.test(lines[i]) &&
      !/^\d+\. /.test(lines[i]) &&
      !/^([-*_])\1{2,}$/.test(lines[i].trim()) &&
      !isTableStart(i)
    ) {
      paraLines.push(lines[i]);
      i++;
    }
    if (paraLines.length > 0) {
      out.push({ kind: "para", inline: parseInline(paraLines.join(" ")) });
    }
  }

  return out;
}

// ─── Inline renderer ─────────────────────────────────────────────────────────

