    gap: 8,
    paddingVertical: 5,
    paddingHorizontal: 12,
    borderBottomWidth: 1,
    borderBottomColor: "#f1f5f9",
  },
  notifSym: {
    fontSize: 13,
    fontWeight: "700",
    width: 16,
    textAlign: "center",
  },
  notifMsg: {
    fontSize: 12,
    flex: 1,
  },

  // Session
  sessionRow: {
    flexDirection: "row",
    alignItems: "flex-start",
    gap: 8,
    paddingVertical: 6,
    paddingHorizontal: 12,
    borderBottomWidth: 1,
    borderBottomColor: "#f1f5f9",
  },
  sessionSym: {
    fontSize: 14,
    fontWeight: "bold",
    width: 18,
    textAlign: "center",
    lineHeight: 20,
  },
  sessionBody: {
    flex: 1,
    flexDirection: "row",
